final:
module RefModule (
    input CLK,
    input D,
    input SET,
    input CLR,
    output reg Q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (SET) Q <= 1'b1;
    else if (CLR) Q <= 1'b0;
    else Q <= D;
end

endmodule
